// UserController.java
@RestController
@RequestMapping("/api/v1/users")
public class UserController {

  private final UserService users;

  public UserController(UserService users) { this.users = users; }

  // GET /api/v1/users?page=0&size=20&search=ada
  @GetMapping
  public Page<UserDto> list(
      @RequestParam(defaultValue = "0") int page,
      @RequestParam(defaultValue = "20") int size,
      @RequestParam(required = false) String search) {
    return users.list(PageRequest.of(page, size), search);
  }

  // GET /api/v1/users/42
  @GetMapping("/{id}")
  public UserDto get(@PathVariable long id) {
    return users.getById(id);   // throws NotFoundException if missing → 404
  }

  // POST /api/v1/users
  @PostMapping
  public ResponseEntity<UserDto> create(@Valid @RequestBody CreateUserRequest req) {
    var created = users.create(req);
    return ResponseEntity
        .created(URI.create("/api/v1/users/" + created.id()))   // 201 + Location
        .body(created);
  }

  // PUT /api/v1/users/42 — replace entire user
  @PutMapping("/{id}")
  public UserDto replace(@PathVariable long id, @Valid @RequestBody UpdateUserRequest req) {
    return users.replace(id, req);
  }

  // PATCH /api/v1/users/42 — partial update
  @PatchMapping("/{id}")
  public UserDto update(@PathVariable long id, @RequestBody PatchUserRequest req) {
    return users.patch(id, req);
  }

  // DELETE /api/v1/users/42
  @DeleteMapping("/{id}")
  public ResponseEntity<Void> delete(@PathVariable long id) {
    users.delete(id);
    return ResponseEntity.noContent().build();   // 204
  }
}

// GlobalExceptionHandler.java — turn exceptions into proper HTTP status codes
@RestControllerAdvice
public class GlobalExceptionHandler {

  @ExceptionHandler(NotFoundException.class)
  public ResponseEntity<ErrorResponse> notFound(NotFoundException e) {
    return ResponseEntity.status(404).body(new ErrorResponse("NOT_FOUND", e.getMessage()));
  }

  @ExceptionHandler(MethodArgumentNotValidException.class)
  public ResponseEntity<ErrorResponse> validation(MethodArgumentNotValidException e) {
    var fields = e.getBindingResult().getFieldErrors().stream()
        .collect(Collectors.toMap(FieldError::getField, DefaultMessageSourceResolvable::getDefaultMessage));
    return ResponseEntity.badRequest().body(new ErrorResponse("VALIDATION", "Invalid input", fields));
  }

  @ExceptionHandler(DuplicateResourceException.class)
  public ResponseEntity<ErrorResponse> conflict(DuplicateResourceException e) {
    return ResponseEntity.status(409).body(new ErrorResponse("CONFLICT", e.getMessage()));
  }
}

record ErrorResponse(String code, String message, Map<String, String> fields) {
  ErrorResponse(String code, String message) { this(code, message, null); }
}
